function main(input) {
  // Slack Web API（chat.postMessage）。トークンはシークレット参照で、平文は script に渡らない。
  // 宛先束縛（slack.com）× egress allowlist はホスト側が URL ホスト部リテラルで照合する。
  const res = Shiki.http.request({
    method: "POST",
    url: "https://slack.com/api/chat.postMessage",
    secret: { name: "slack-bot-token" },
    body: { channel: input.channel, text: input.text },
  });
  // Slack は失敗も HTTP 200 + { ok:false, error } で返す（missing_scope / not_in_channel /
  // rate_limited 等）。ステップ/run を誤って成功扱いにしないよう、ok!==true は明示的に throw する。
  if (res.status < 200 || res.status >= 300 || !res.body || res.body.ok !== true) {
    const err = res.body && res.body.error ? res.body.error : ("http_" + res.status);
    throw new Error("slack chat.postMessage failed: " + err);
  }
  return { ok: true, channel: res.body.channel, ts: res.body.ts };
}
